775→         * Flushes the current (or pending) batch to the log. When the batch is written
   776→         * locally, a new snapshot is created in the snapshot registry and the events
   777→         * associated with the batch are added to the deferred event queue.
   778→         */
   779→        private void flushCurrentBatch() {
   780→            if (currentBatch != null) {
   781→                try {
   782→                    if (currentBatch.builder.numRecords() == 0) {
   783→                        // The only way we can get here is if append() has failed in an unexpected
   784→                        // way and left an empty batch. Try to clean it up.
   785→                        log.debug("Tried to flush an empty batch for {}.", tp);
   786→                        // There should not be any deferred events attached to the batch. We fail
   787→                        // the batch just in case. As a side effect, coordinator state is also
   788→                        // reverted, but there should be no changes since the batch was empty.
   789→                        failCurrentBatch(new IllegalStateException("Record batch was empty"));
   790→                        return;
   791→                    }
   792→
   793→                    long flushStartMs = time.milliseconds();
   794→                    // Write the records to the log and update the last written offset.
   795→                    long offset = partitionWriter.append(
   796→                        tp,
   797→                        currentBatch.verificationGuard,
   798→                        currentBatch.builder.build()
   799→                    );
   800→                    runtimeMetrics.recordFlushTime(time.milliseconds() - flushStartMs);
   801→                    coordinator.updateLastWrittenOffset(offset);
   802→
